  7	  useModal,
  8	} from '@openshift-console/dynamic-plugin-sdk';
  9	import { getLatestPipelineRunStatus } from '../../../components/utils/pipeline-utils';
 10	import {
 11	  getTaskRunsOfPipelineRun,
 12	  useTaskRunsK8s,
 13	} from '../../../components/hooks/useTaskRuns';
 14	import Status from '../../../components/status/Status';
 15	import { PipelineRunModel } from '../../../models';
 16	import { resourcePathFromModel } from '../../../components/utils/utils';
 17	import { startPipelineModal } from '../../../components/start-pipeline';
 18	import { PipelineKind, PipelineRunKind } from '../../../types';
 19	import BuildDecoratorBubble from '../BuildDecoratorBubble';
 20	import PipelineBuildDecoratorTooltip from './PipelineBuildDecoratorTooltip';
 21	import { t } from '../../utils/common-utils';
 22	
 23	type PipelineRunDecoratorProps = {
 24	  pipeline: PipelineKind;
 25	  pipelineRuns: PipelineRunKind[];
 26	  radius: number;
 27	  x: number;
 28	  y: number;
 29	};
 30	
 31	type StateProps = {
 32	  impersonate?: {
 33	    kind: string;
 34	    name: string;
 35	    subprotocols: string[];
 36	  };
 37	};
 38	
 39	export const ConnectedPipelineRunDecorator: React.FC<
 40	  PipelineRunDecoratorProps & StateProps
 41	> = ({ pipeline, pipelineRuns, radius, x, y, impersonate }) => {
 42	  const ref = React.useRef();
 43	  const launchModal = useModal();
 44	
 45	  const { latestPipelineRun, status } =
 46	    getLatestPipelineRunStatus(pipelineRuns);
 47	  const [taskRuns, taskRunsLoaded] = useTaskRunsK8s(
 48	    latestPipelineRun?.metadata?.namespace,
 49	  );
 50	
 51	  const PLRTaskRuns = getTaskRunsOfPipelineRun(
 52	    taskRuns,
 53	    latestPipelineRun?.metadata?.name,
 54	  );
 55	  const statusIcon = <Status status={status} iconOnly noTooltip />;
 56	
 57	  const defaultAccessReview: AccessReviewResourceAttributes = {
 58	    group: PipelineRunModel.apiGroup,
 59	    resource: PipelineRunModel.plural,
 60	    namespace: pipeline.metadata.namespace,
 61	    verb: 'create',
 62	  };
 63	  const canStartPipeline = useAccessReview(defaultAccessReview, impersonate);
 64	
 65	  let ariaLabel;
 66	  let tooltipContent;
 67	  let decoratorContent;
 68	  if (latestPipelineRun) {
 69	    ariaLabel = t(`Pipeline status is {{status}}. View logs.`, { status });
 70	    tooltipContent = taskRunsLoaded && (
 71	      <PipelineBuildDecoratorTooltip
 72	        pipelineRun={latestPipelineRun}
 73	        status={status}
 74	        taskRuns={PLRTaskRuns}
 75	      />
 76	    );
 77	
 78	    const link = `${resourcePathFromModel(
 79	      PipelineRunModel,
 80	      latestPipelineRun.metadata.name,
 81	      latestPipelineRun.metadata.namespace,
 82	    )}/logs`;
 83	    decoratorContent = (
 84	      <Link to={link}>
 85	        <BuildDecoratorBubble x={x} y={y} radius={radius} ariaLabel={ariaLabel}>
 86	          {statusIcon}
 87	        </BuildDecoratorBubble>
 88	      </Link>
 89	    );
 90	  } else {
 91	    ariaLabel = t('Pipeline not started. Start pipeline.');
 92	    tooltipContent = t('Pipeline not started');
 93	
 94	    let onClick = null;
 95	    if (canStartPipeline) {
 96	      onClick = () => {
 97	        launchModal(startPipelineModal, {
 98	          pipeline,
 99	        });
100	      };
101	    }
102	
103	    decoratorContent = (
104	      <BuildDecoratorBubble
105	        x={x}
106	        y={y}
107	        radius={radius}
108	        onClick={onClick}
109	        ariaLabel={ariaLabel}
110	      >
111	        {statusIcon}
112	      </BuildDecoratorBubble>
113	    );
114	  }
115	
116	  return (
117	    <Tooltip
118	      triggerRef={ref}
119	      content={tooltipContent}
120	      position={TooltipPosition.left}
121	    >
122	      <g ref={ref} data-test="PipelineRunDecorator">
123	        {decoratorContent}
124	      </g>
125	    </Tooltip>
126	  );
127	};
128	
129	export default ConnectedPipelineRunDecorator;

