 70	  },
 71	}));
 72	
 73	describe('ConnectedPipelineRunDecorator (RTL)', () => {
 74	  const mockUseAccessReview = useAccessReview as jest.Mock;
 75	  const mockUseTaskRunsK8s = useTaskRunsK8s as jest.Mock;
 76	  const mockGetTaskRunsOfPipelineRun = getTaskRunsOfPipelineRun as jest.Mock;
 77	  const mockStatus = Status as jest.Mock;
 78	
 79	  beforeEach(() => {
 80	    jest.clearAllMocks();
 81	    mockUseAccessReview.mockReturnValue([true, true]);
 82	    mockUseTaskRunsK8s.mockReturnValue([[], true]);
 83	    mockGetTaskRunsOfPipelineRun.mockReturnValue([]);
 84	  });
 85	
 86	  it('renders a Link when a PipelineRun is available', () => {
 87	    render(
 88	      <MemoryRouter>
 89	        <SVGDefsProvider>
 90	          <ConnectedPipelineRunDecorator
 91	            pipeline={connectedPipelineOne.pipeline}
 92	            pipelineRuns={connectedPipelineOne.pipelineRuns}
 93	            radius={10}
 94	            x={5}
 95	            y={5}
 96	          />
 97	        </SVGDefsProvider>
 98	      </MemoryRouter>,
 99	    );
100	
101	    const link = screen.getByRole('link');
102	    expect(link).toBeDefined();
103	    expect(link.getAttribute('href')).not.toBeNull();
104	    expect(link.getAttribute('href')).toMatch(/\/logs$/);
105	  });
106	
107	  it('renders a clickable bubble when no PipelineRuns but has permission', () => {
108	    mockStatus.mockImplementationOnce(() => (
109	      <div aria-label="Pipeline not started">Pipeline not started</div>
110	    ));
111	
112	    render(
113	      <MemoryRouter>
114	        <SVGDefsProvider>
115	          <ConnectedPipelineRunDecorator
116	            pipeline={connectedPipelineOne.pipeline}
117	            pipelineRuns={[]}
118	            radius={10}
119	            x={5}
120	            y={5}
121	          />
122	        </SVGDefsProvider>
123	      </MemoryRouter>,
124	    );
125	
126	    const bubble = screen.getByLabelText(/Pipeline not started/i);
127	    expect(bubble).toBeDefined();
128	  });
129	
130	  it('renders a non-clickable bubble when no PipelineRuns and no permission', () => {
131	    mockUseAccessReview.mockReturnValue([false, true]);
132	    mockStatus.mockImplementationOnce(() => (
133	      <div aria-label="Pipeline not started">Pipeline not started</div>
134	    ));
135	
136	    render(
137	      <MemoryRouter>
138	        <SVGDefsProvider>
139	          <ConnectedPipelineRunDecorator
140	            pipeline={connectedPipelineOne.pipeline}
141	            pipelineRuns={[]}
142	            radius={10}
143	            x={5}
144	            y={5}
145	          />
146	        </SVGDefsProvider>
147	      </MemoryRouter>,
148	    );
149	
150	    const bubble = screen.getByLabelText(/Pipeline not started/i);
151	    expect(bubble).toBeDefined();
152	    expect(screen.queryByRole('link')).toBeNull();
153	  });
154	});

